import{_ as a,o as l,c as e,a2 as n}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"黃豆 — 台股相關個股深度整理","description":"","frontmatter":{},"headers":[],"relativePath":"Deep32Q知識庫/產業洞察/黃豆研究/黃豆研究_台股相關個股深度整理.md","filePath":"Deep32Q知識庫/產業洞察/黃豆研究/黃豆研究_台股相關個股深度整理.md"}'),s={name:"Deep32Q知識庫/產業洞察/黃豆研究/黃豆研究_台股相關個股深度整理.md"};function i(r,t,d,g,p,o){return l(),e("div",null,[...t[0]||(t[0]=[n(`<h1 id="黃豆-—-台股相關個股深度整理" tabindex="-1">黃豆 — 台股相關個股深度整理 <a class="header-anchor" href="#黃豆-—-台股相關個股深度整理" aria-label="Permalink to &quot;黃豆 — 台股相關個股深度整理&quot;">​</a></h1><p><strong>分類</strong>：產業洞察／黃豆研究／台股供應鏈 <strong>日期</strong>：2026-05-07 <strong>作者</strong>：Gale 分析 <strong>狀態</strong>：✅ 完成 <strong>關聯報告</strong>：黃豆：從飼料到燃料＿定價權的結構性轉移.md</p><hr><h2 id="摘要" tabindex="-1">摘要 <a class="header-anchor" href="#摘要" aria-label="Permalink to &quot;摘要&quot;">​</a></h2><p>2026 年黃豆市場經歷結構性轉變：<strong>定價權從中國飼料需求轉移至美國生質柴油政策（RFS Set 2）</strong>，壓榨利潤創 2.5 年高，豆油合約創歷史新高。此背景下，台股相關個股所受影響可分為三類：</p><ol><li><strong>飼料/肉品加工廠</strong>（大成、卜蜂）：黃豆是成本，<strong>高黃豆價 = 成本壓力</strong></li><li><strong>油脂製造商</strong>（福壽、泰山、福懋油）：黃豆是原料，<strong>壓榨利潤擴大 = 利多</strong></li><li><strong>小型/專業廠</strong>（台榮、興泰）：邊際影響，視業務組合而定</li></ol><hr><h2 id="關鍵傳導鏈-重新釐清" tabindex="-1">關鍵傳導鏈（重新釐清） <a class="header-anchor" href="#關鍵傳導鏈-重新釐清" aria-label="Permalink to &quot;關鍵傳導鏈（重新釐清）&quot;">​</a></h2><p>根據我們的結構性分析：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>RFS Set 2（55% 跳增）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>美國國內黃豆油需求暴增（17.3B 磅/年）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>壓榨利潤創 2.5 年高（豆油漲幅 &gt; 黃豆漲幅）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>CBOT 黃豆期貨跟漲（但漲幅小於豆油）</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>台灣進口黃豆成本上升</span></span>
<span class="line"><span>    ↓</span></span>
<span class="line"><span>┌──────────────────┬─────────────────────┐</span></span>
<span class="line"><span>│   飼料廠           │   油脂廠              │</span></span>
<span class="line"><span>│  （大成/卜蜂）     │  （福壽/泰山/福懋油）    │</span></span>
<span class="line"><span>│  成本↑             │  壓榨利潤↑（理論上）    │</span></span>
<span class="line"><span>│  利潤↓             │  （實際上受台灣市場結構影響）│</span></span>
<span class="line"><span>└──────────────────┴─────────────────────┘</span></span></code></pre></div><hr><h2 id="一、公司深度分析" tabindex="-1">一、公司深度分析 <a class="header-anchor" href="#一、公司深度分析" aria-label="Permalink to &quot;一、公司深度分析&quot;">​</a></h2><h3 id="_1️⃣-大成-1210-—-台灣最大飼料-肉品廠" tabindex="-1">1️⃣ 大成 (1210) — 台灣最大飼料/肉品廠 <a class="header-anchor" href="#_1️⃣-大成-1210-—-台灣最大飼料-肉品廠" aria-label="Permalink to &quot;1️⃣ 大成 (1210) — 台灣最大飼料/肉品廠&quot;">​</a></h3><p><strong>基本資料</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:right;">數據</th></tr></thead><tbody><tr><td style="text-align:left;">股價（5/6）</td><td style="text-align:right;">NT$52.00</td></tr><tr><td style="text-align:left;">2026 Q1 營收</td><td style="text-align:right;">265.65 億（+4% YoY）</td></tr><tr><td style="text-align:left;">2025 毛利率</td><td style="text-align:right;">~15%</td></tr><tr><td style="text-align:left;">業務結構</td><td style="text-align:right;">飼料 54.4% / 食品 19.7% / 肉品 18.6% / 油脂 少量</td></tr></tbody></table><p><strong>黃豆關聯度</strong>：🟡🟡🟡🟡🟡（極高）</p><p>大成是台灣最大的飼料生產商，年消耗數百萬噸黃豆（進口）。飼料成本中，黃豆佔約 30-40%（另為玉米）。</p><p><strong>2026 成本情境</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">情境</th><th style="text-align:right;">CBOT 黃豆</th><th style="text-align:left;">對大成影響</th></tr></thead><tbody><tr><td style="text-align:left;">基底（無戰爭）</td><td style="text-align:right;">$10.20-11.00</td><td style="text-align:left;">✅ 成本溫和，利潤正常</td></tr><tr><td style="text-align:left;"><strong>當前（戰爭 + RFS）</strong></td><td style="text-align:right;"><strong>$11.50-12.00</strong></td><td style="text-align:left;">⚠️ 成本升，公司稱庫存可撐 Q2</td></tr><tr><td style="text-align:left;">全面升級</td><td style="text-align:right;">$12.50-14.00</td><td style="text-align:left;">🔴 下半年壓力大增，需調價</td></tr></tbody></table><p><strong>公司因應策略</strong>：</p><ul><li>目前原料庫存可支撐到 Q2 底</li><li>下半年將視市場調漲飼料售價</li><li>新產能擴張中：水產飼料廠（年產值 30 億，已投產）、土雞加工廠（年產值 3 億）、全能生技廠 + 肉品分切廠（預計 2026/7 投產，合計 32 億）</li><li>越南畜牧場 + 美國冷凍食品持續擴張</li></ul><p><strong>結論</strong>：高黃豆價格對大成是<strong>成本壓力</strong>，需觀察公司轉嫁能力。若 CBOT 維持 $11.50-12.50，大成全年 EPS 可能被壓縮。買大成等於是<strong>賭飼料價格能順利轉嫁</strong>，不是純黃豆多單的替代。</p><hr><h3 id="_2️⃣-卜蜂-1215-—-台灣第二大飼料-肉品廠" tabindex="-1">2️⃣ 卜蜂 (1215) — 台灣第二大飼料/肉品廠 <a class="header-anchor" href="#_2️⃣-卜蜂-1215-—-台灣第二大飼料-肉品廠" aria-label="Permalink to &quot;2️⃣ 卜蜂 (1215) — 台灣第二大飼料/肉品廠&quot;">​</a></h3><p><strong>基本資料</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:right;">數據</th></tr></thead><tbody><tr><td style="text-align:left;">股價（5/6）</td><td style="text-align:right;">NT$139.50</td></tr><tr><td style="text-align:left;">2026 Q1 累計營收</td><td style="text-align:right;">71.76 億（+7.16% YoY）</td></tr><tr><td style="text-align:left;">2025 毛利率</td><td style="text-align:right;">21%+</td></tr><tr><td style="text-align:left;">EPS 預估（統一證）</td><td style="text-align:right;">6.92 元（法人區間 6.92-10.98）</td></tr></tbody></table><p><strong>黃豆關聯度</strong>：🟡🟡🟡🟡🟡（極高）</p><p>卜蜂同樣是飼料/畜牧垂直整合大廠，黃豆為飼料核心原料之一。</p><p><strong>2026 壓力點</strong>：</p><ul><li>國際油價攀升推升運費 3-5 成</li><li>玉米+黃豆因生質燃料需求排擠飼料供給</li><li>公司目前約 3 個月低價庫存提供緩衝</li><li>若原料續漲，飼料價格可能上調</li></ul><p><strong>因應策略</strong>：</p><ul><li>垂直整合：自有農場 + 直營通路</li><li>強化食品加工（高毛利產品）</li><li>成本轉嫁能力較大成強（市佔率較高 + 品牌力）</li></ul><p><strong>結論</strong>：卜蜂毛利結構較大成好（21% vs 15%），緩衝空間較大。但高黃豆價格仍是逆風。若看好黃豆繼續上漲，卜蜂不是適合的標的。</p><hr><h3 id="_3️⃣-福壽-1219-—-百年油脂-飼料-食品廠" tabindex="-1">3️⃣ 福壽 (1219) — 百年油脂/飼料/食品廠 <a class="header-anchor" href="#_3️⃣-福壽-1219-—-百年油脂-飼料-食品廠" aria-label="Permalink to &quot;3️⃣ 福壽 (1219) — 百年油脂/飼料/食品廠&quot;">​</a></h3><p><strong>基本資料</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:right;">數據</th></tr></thead><tbody><tr><td style="text-align:left;">股價（5/6）</td><td style="text-align:right;">NT$13.40</td></tr><tr><td style="text-align:left;">2026 Q1 累計營收</td><td style="text-align:right;">待確認（飼料穀物平穩向上預期）</td></tr><tr><td style="text-align:left;">業務</td><td style="text-align:right;">食用油、飼料、肥料、寵物食品、肉品（洽富氣冷雞）</td></tr></tbody></table><p><strong>黃豆關聯度</strong>：🟡🟡🟡🟡🟡（極高 — 垂直整合油脂 + 飼料）</p><p>福壽的特點：<strong>既做油脂也做飼料</strong>，黃豆價格上漲對兩邊影響互相抵銷。</p><ul><li>油脂端：高黃豆油價有助維持榨油利潤</li><li>飼料端：高黃豆成本壓縮飼料利潤</li><li>1970 年代曾是美援黃豆溶劑提油工廠，技術底蘊深厚</li><li>洽富氣冷雞已供應星宇航空全艙等 + 部分華航，預計 2026 年轉虧為盈</li></ul><p><strong>結論</strong>：業務雙面性使福壽對黃豆價格波動較大成/卜蜂中性。公司預期飼料原料價格「平穩向上」，股價低（13.4 元）但流動性低，不適合大資金。</p><hr><h3 id="_4️⃣-泰山-1218-—-老牌油脂-飲料-食品廠" tabindex="-1">4️⃣ 泰山 (1218) — 老牌油脂/飲料/食品廠 <a class="header-anchor" href="#_4️⃣-泰山-1218-—-老牌油脂-飲料-食品廠" aria-label="Permalink to &quot;4️⃣ 泰山 (1218) — 老牌油脂/飲料/食品廠&quot;">​</a></h3><p><strong>基本資料</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:right;">數據</th></tr></thead><tbody><tr><td style="text-align:left;">股價（5/6）</td><td style="text-align:right;">NT$18.85</td></tr><tr><td style="text-align:left;">2025 已轉虧為盈</td><td style="text-align:right;">經營權易主後</td></tr><tr><td style="text-align:left;">業務</td><td style="text-align:right;">油脂（沙拉油）、飲料、食品、食糧</td></tr></tbody></table><p><strong>黃豆關聯度</strong>：🟡🟡🟡🟡（高 — 油脂為核心業務之一）</p><p>泰山從油脂起家（1968 年沙拉油），黃豆主要來自美國和巴西。油脂仍為主要營收來源之一。</p><p><strong>2026 動向</strong>：</p><ul><li>經營權易主後聚焦三大成長動能：消費食品、食糧事業、國際布局</li><li>預計推出近百種新產品</li><li>深化商用食糧市場（連鎖餐飲 + 中央廚房）</li><li>北美零售通路、日本熊本市場拓展</li></ul><p><strong>結論</strong>：泰山油脂業務受惠高黃豆油價格，但非純油脂股（飲料食品佔比也大）。18.85 元價位接近淨值，若有整頓故事可能有趣，但不宜當作純黃豆題材。</p><hr><h3 id="_5️⃣-福懋油-1225-—-純油脂-飼料" tabindex="-1">5️⃣ 福懋油 (1225) — 純油脂/飼料 <a class="header-anchor" href="#_5️⃣-福懋油-1225-—-純油脂-飼料" aria-label="Permalink to &quot;5️⃣ 福懋油 (1225) — 純油脂/飼料&quot;">​</a></h3><p><strong>基本資料</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:right;">數據</th></tr></thead><tbody><tr><td style="text-align:left;">股價（5/6）</td><td style="text-align:right;">NT$33.15</td></tr><tr><td style="text-align:left;">2026 Q1 營收</td><td style="text-align:right;">32.81 億（+1.88% YoY）</td></tr><tr><td style="text-align:left;">業務</td><td style="text-align:right;">沙拉油、飼料、麵粉</td></tr></tbody></table><p><strong>黃豆關聯度</strong>：🟡🟡🟡🟡（高 — 油脂為主力）</p><p>福懋油以油脂業務為主，沙拉油（黃豆油）佔比高於飼料。在壓榨利潤擴大的環境下，<strong>理論上是台股中最受惠的純油脂標的之一</strong>。</p><p><strong>但需注意</strong>：</p><ul><li>台灣黃豆油市場是內需市場，與美國生質柴油市場無直接連動</li><li>福懋油的利潤取決於：<strong>台灣沙拉油定價能力</strong> vs <strong>CBOT 黃豆進口成本</strong></li><li>若 CBOT 漲但國內沙拉油無法同比例漲價，壓榨利潤反而被壓縮</li></ul><p><strong>結論</strong>：潛在受惠標的，但需追蹤台灣沙拉油終端價格是否能跟漲。</p><hr><h3 id="_6️⃣-台榮-1220-—-小規模飼料-麵粉" tabindex="-1">6️⃣ 台榮 (1220) — 小規模飼料/麵粉 <a class="header-anchor" href="#_6️⃣-台榮-1220-—-小規模飼料-麵粉" aria-label="Permalink to &quot;6️⃣ 台榮 (1220) — 小規模飼料/麵粉&quot;">​</a></h3><p><strong>基本資料</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:right;">數據</th></tr></thead><tbody><tr><td style="text-align:left;">股價（5/6）</td><td style="text-align:right;">NT$12.35</td></tr><tr><td style="text-align:left;">2026 前 4 月營收</td><td style="text-align:right;">10.00 億（-2.39% YoY）</td></tr><tr><td style="text-align:left;">業務</td><td style="text-align:right;">飼料、麵粉、大宗穀物</td></tr></tbody></table><p><strong>黃豆關聯度</strong>：🟡🟡🟡（中 — 飼料用黃豆）</p><p>小規模飼料廠，對黃豆價格敏感但規模效應不足。股價低（12.35 元）、交易量小，不具備操作價值。</p><hr><h3 id="_7️⃣-興泰-1235-—-微量飼料" tabindex="-1">7️⃣ 興泰 (1235) — 微量飼料 <a class="header-anchor" href="#_7️⃣-興泰-1235-—-微量飼料" aria-label="Permalink to &quot;7️⃣ 興泰 (1235) — 微量飼料&quot;">​</a></h3><p><strong>基本資料</strong></p><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:right;">數據</th></tr></thead><tbody><tr><td style="text-align:left;">股價（5/6）</td><td style="text-align:right;">NT$44.75</td></tr><tr><td style="text-align:left;">2026 Q1 營收</td><td style="text-align:right;">6,677 萬（+134.94% YoY！但基期極低）</td></tr><tr><td style="text-align:left;">業務</td><td style="text-align:right;">飼料、農畜牧</td></tr></tbody></table><p><strong>黃豆關聯度</strong>：🟡（低 — 規模極小）</p><p>營收基期太低（月營收 2-3 千萬），不具備代表性。高成長率來自低基期效應。</p><hr><h2 id="二、投資框架-如何用黃豆研究來操作台股" tabindex="-1">二、投資框架：如何用黃豆研究來操作台股 <a class="header-anchor" href="#二、投資框架-如何用黃豆研究來操作台股" aria-label="Permalink to &quot;二、投資框架：如何用黃豆研究來操作台股&quot;">​</a></h2><h3 id="核心矛盾" tabindex="-1">核心矛盾 <a class="header-anchor" href="#核心矛盾" aria-label="Permalink to &quot;核心矛盾&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>我們的研究方向：黃豆價格 → 偏多（RFS + 伊朗戰爭持續）</span></span>
<span class="line"><span>                ↓</span></span>
<span class="line"><span>台股誰受惠？問題比想像中複雜：</span></span>
<span class="line"><span>  油脂廠（福壽/泰山/福懋油）</span></span>
<span class="line"><span>    → 受惠：CBOT 黃豆油價格上漲</span></span>
<span class="line"><span>    → 但受限：台灣沙拉油是管制/寡佔市場，成本轉嫁不一定順暢</span></span>
<span class="line"><span></span></span>
<span class="line"><span>  飼料廠（大成/卜蜂）</span></span>
<span class="line"><span>    → 受害：進口黃豆成本上升</span></span>
<span class="line"><span>    → 但可轉嫁：飼料價格可調漲，只是有時間差</span></span>
<span class="line"><span></span></span>
<span class="line"><span>結論：沒有「純黃豆多頭概念股」這種東西。</span></span>
<span class="line"><span>      台股的飼料/油脂公司是成本轉嫁的博弈，不是期貨的替代。</span></span></code></pre></div><h3 id="真正該關注的" tabindex="-1">真正該關注的 <a class="header-anchor" href="#真正該關注的" aria-label="Permalink to &quot;真正該關注的&quot;">​</a></h3><p>如果你認同我們的黃豆結構性多頭論述（RFS + 戰爭），在台股中：</p><table tabindex="0"><thead><tr><th style="text-align:left;">標的</th><th style="text-align:left;">性質</th><th style="text-align:right;">最受益於</th><th style="text-align:left;">風險</th></tr></thead><tbody><tr><td style="text-align:left;">福懋油 (1225)</td><td style="text-align:left;">最純油脂股</td><td style="text-align:right;">壓榨利差擴大</td><td style="text-align:left;">台灣內需市場漲價受限</td></tr><tr><td style="text-align:left;">福壽 (1219)</td><td style="text-align:left;">油脂+飼料</td><td style="text-align:right;">兩邊互補</td><td style="text-align:left;">流動性差、股價低</td></tr><tr><td style="text-align:left;">大成 (1210)</td><td style="text-align:left;">飼料龍頭</td><td style="text-align:right;">飼料降價時</td><td style="text-align:left;">高黃豆=逆風，不建議</td></tr><tr><td style="text-align:left;">卜蜂 (1215)</td><td style="text-align:left;">飼料/肉品</td><td style="text-align:right;">飼料降價時</td><td style="text-align:left;">同大成，但毛利較高</td></tr></tbody></table><h3 id="更好的策略" tabindex="-1">更好的策略 <a class="header-anchor" href="#更好的策略" aria-label="Permalink to &quot;更好的策略&quot;">​</a></h3><p><strong>如果你看多黃豆，直接做 CBOT 期貨，比買台股更純粹。</strong></p><p>台股這些公司：</p><ul><li>股價受大盤氣氛影響更大</li><li>管理層的 hedging 策略未知</li><li>成本轉嫁有時間差（約 1-2 季）</li><li>台灣內需市場價格僵固</li></ul><p><strong>唯一有意義的台股黃豆情境</strong>：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>情境：黃豆價格從 $12 跌回 $10-10.50</span></span>
<span class="line"><span>→ 大成/卜蜂飼料成本大幅下降</span></span>
<span class="line"><span>→ 雞豬價格若維持高檔（需求剛性）</span></span>
<span class="line"><span>→ 飼料廠利差暴增</span></span>
<span class="line"><span>→ 大成/卜蜂才有較明顯的獲利跳升</span></span></code></pre></div><p>這與我們目前的劇本（黃豆偏多）<strong>方向相反</strong>。所以目前台股黃豆概念股沒有理想的做多機會。</p><hr><h2 id="三、結論" tabindex="-1">三、結論 <a class="header-anchor" href="#三、結論" aria-label="Permalink to &quot;三、結論&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">問題</th><th style="text-align:right;">答案</th></tr></thead><tbody><tr><td style="text-align:left;">台股有純黃豆多頭概念股嗎？</td><td style="text-align:right;">❌ 沒有</td></tr><tr><td style="text-align:left;">油脂廠真的受惠嗎？</td><td style="text-align:right;">⚠️ 理論上受惠壓榨利差，實際上轉嫁有限</td></tr><tr><td style="text-align:left;">現在該買大成/卜蜂嗎？</td><td style="text-align:right;">❌ 不建議，高黃豆是逆風</td></tr><tr><td style="text-align:left;">如果黃豆大跌該買誰？</td><td style="text-align:right;">✅ 大成 (1210) — EPS 敏感度最高</td></tr><tr><td style="text-align:left;">更好的做法？</td><td style="text-align:right;">CBOT ZS 期貨直接做</td></tr><tr><td style="text-align:left;">追蹤重點？</td><td style="text-align:right;">① CBOT 黃豆油/黃豆價差（壓榨利潤指標）② 台灣沙拉油零售價 ③ 飼料價格調整幅度</td></tr></tbody></table><hr><p><strong>下次更新</strong>：觀察 5/12 WASDE 後、5/14 川習會後、以及台灣飼料廠 Q1 財報公布後的法人評論。</p><p><strong>文件資訊</strong>：</p><ul><li>路徑：<code>/Users/kaipro/.openclaw/skills/NEW_Deep32Q/Deep32Q知識庫/產業洞察/黃豆研究/黃豆研究_台股相關個股深度整理.md</code></li><li>更新：2026-05-07</li></ul>`,92)])])}const y=a(s,[["render",i]]);export{x as __pageData,y as default};
